import sys
from typing import List

class Solution:
    def solve(self, nums: List[int]) -> bool:
        n = len(nums)
        result = []
        for i in range(n):
            if not result or nums[i] != result[-1]:
                result.append(nums[i])
        return len(result)

if __name__ == '__main__':
    s = Solution()
    nums = list(map(int, input().split()))
    n = int(input())
    print(s.solve(nums))

